if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Auth Guard').first().json;
const action = (body.action || 'list').toLowerCase();
const esc = s => (s || '').replace(/'/g, "''");
let query = '';
let meta = { action };

switch (action) {
  case 'upsert':
  case 'create':
    query = `INSERT INTO gda_contract_vehicles (vehicle_name, contract_number, idiq_type, agency, issuing_office, naics_codes, ceiling_value, period_of_performance, set_aside, gda_position, prime_or_sub, teaming_partners, on_ramp_eligible, on_ramp_window, notes, sam_url, govtribe_id, source, updated_at)
      VALUES ('${esc(body.vehicle_name)}', '${esc(body.contract_number)}', '${esc(body.idiq_type || 'Multi-Award')}', '${esc(body.agency)}', '${esc(body.issuing_office)}', '${esc(body.naics_codes)}', ${parseFloat(body.ceiling_value) || 0}, '${esc(body.period_of_performance)}', '${esc(body.set_aside)}', '${esc(body.gda_position || 'Not Positioned')}', '${esc(body.prime_or_sub || 'Unknown')}', '${esc(body.teaming_partners)}', ${body.on_ramp_eligible || false}, '${esc(body.on_ramp_window)}', '${esc(body.notes)}', '${esc(body.sam_url)}', '${esc(body.govtribe_id)}', '${esc(body.source || 'Manual')}', NOW())
      ON CONFLICT (contract_number) DO UPDATE SET
        vehicle_name = EXCLUDED.vehicle_name,
        agency = COALESCE(NULLIF(EXCLUDED.agency,''), gda_contract_vehicles.agency),
        ceiling_value = CASE WHEN EXCLUDED.ceiling_value > 0 THEN EXCLUDED.ceiling_value ELSE gda_contract_vehicles.ceiling_value END,
        gda_position = COALESCE(NULLIF(EXCLUDED.gda_position,'Not Positioned'), gda_contract_vehicles.gda_position),
        on_ramp_eligible = EXCLUDED.on_ramp_eligible,
        on_ramp_window = COALESCE(NULLIF(EXCLUDED.on_ramp_window,''), gda_contract_vehicles.on_ramp_window),
        notes = COALESCE(NULLIF(EXCLUDED.notes,''), gda_contract_vehicles.notes),
        updated_at = NOW()
      RETURNING *;`;
    meta.action = 'upsert';
    break;
  case 'delete':
    query = `DELETE FROM gda_contract_vehicles WHERE id = ${parseInt(body.id) || 0} RETURNING id, vehicle_name;`;
    break;
  case 'search':
    const q = esc(body.q || '');
    query = `SELECT * FROM gda_contract_vehicles WHERE vehicle_name ILIKE '%${q}%' OR contract_number ILIKE '%${q}%' OR agency ILIKE '%${q}%' ORDER BY updated_at DESC LIMIT 25;`;
    break;
  case 'on_ramp':
    query = `SELECT * FROM gda_contract_vehicles WHERE on_ramp_eligible = true ORDER BY on_ramp_window ASC, ceiling_value DESC;`;
    break;
  default:
    const limit = parseInt(body.limit) || 50;
    query = `SELECT * FROM gda_contract_vehicles ORDER BY ceiling_value DESC NULLS LAST, updated_at DESC LIMIT ${limit};`;
    meta.action = 'list';
}
return [{ json: { query, meta } }];

const meta = $('Build Query').first().json.meta;
const rows = $input.all().map(i => i.json).filter(r => r.id !== undefined);
const resp = { status: 'ok', action: meta.action };
if (meta.action === 'upsert' || meta.action === 'create') resp.vehicle = rows[0] || null;
else if (meta.action === 'delete') resp.deleted = rows[0] || null;
else { resp.vehicles = rows; resp.count = rows.length; }
resp.timestamp = new Date().toISOString();
return [{ json: resp }];
